UpdateContext(
    {
        locLoopCounter: 0,
        locLoopRepeat: true,
        locJobEntryRecord: LookUp(
            AddColumns(
                colCdsJobEntryOptions,
                RowNumber,
                locLoopCounter
            ),
            'Job Entry Option' = gblRecordJobEntryOption_Hierarchy.'Job Entry Option'
        ),
        locLoadingCompleted: false
    }
);

