//// Navigate to previous screen
// reset controls
Reset(gal_Options_Selection);
// previous screen
Navigate('Windows Screen');

Navigate(
    'Add Note Screen',
    ScreenTransition.None,
    {
        locRecordNoteCurrent: {
            TableName: "Job Entry Selections",
            GUID: gblRecordJobEntrySelection.'Job Entry Selection',
            BackScreen: App.ActiveScreen,
            Notes: gblRecordJobEntrySelection.Notes
        }
    }
);

//Remove any row numbers lower than the current position
ClearCollect(
    colJobEntryOptionHierarchy,
    Filter(
        colJobEntryOptionHierarchy,
        RowNumber >= gblRecordJobEntryOption_Hierarchy.RowNumber
    )
);
Patch(
    colJobEntryOptionHierarchy,
    Last(
        Sort(
            colJobEntryOptionHierarchy,
            RowNumber,
            SortOrder.Descending
        )
    ),
    ThisItem
);
// Add new row or update final row of left menu collection
If(
    Last(
        Sort(
            colJobEntryOptionHierarchy,
            RowNumber,
            SortOrder.Descending
        )
    ).Type <> gblOptionSets.JobEntryOption.Type.Value,
    Patch(
        colJobEntryOptionHierarchy,
        Defaults(colJobEntryOptionHierarchy),
        {RowNumber: gblRecordJobEntryOption_Hierarchy.RowNumber - 1}
    )
);
// Go to the next step in the heirarchy
If(
    ThisItem.Type <> gblOptionSets.JobEntryOption.Type.Value,
    Set(
        gblRecordJobEntryOption_Hierarchy,
        LookUp(
            AddColumns(
                colCdsJobEntryOptions,
                RowNumber,
                gblRecordJobEntryOption_Hierarchy.RowNumber - 1
            ),
            'Parent Option'.'Job Entry Option' = ThisItem.'Job Entry Option'
        )
    )
);
If(
    ThisItem.Type = gblOptionSets.JobEntryOption.Type.Value,
    UpdateContext(
        {
            locSelectedValue: LookUp(
                colCdsJobEntryOptions,
                colCdsJobEntryOptions[@'Job Entry Option'] = ThisItem.'Job Entry Option'
            )
        }
    );
    UpdateContext({locShowSaveButton: true});
);
Reset(gal_Options_Selected)

// Increment Counter, Stop Timer (Repeat)
UpdateContext(
    {
        locLoopCounter: locLoopCounter + 1,
        locLoopRepeat: false
    }
);
// Collect Current Option (either initial Value,or last loop)
Collect(
    colJobEntryOptionHierarchy,
    locJobEntryRecord
);
Patch(
    colJobEntryOptionHierarchy,
    locJobEntryRecord,
    {RowNumber: locLoopCounter}
);
// Lookup Parent (next) Option for the Current Option
UpdateContext(
    {
        locJobEntryRecord_Next: LookUp(
            colCdsJobEntryOptions,
            'Job Entry Option' = locJobEntryRecord.'Parent Option'.'Job Entry Option'
        )
    }
);
// If we find a parent, then set it as the 'Current' Option for next loop, and restart timer (loop)
If(
    !IsBlankOrError(locJobEntryRecord_Next) Or locLoopCounter > 20,
    UpdateContext({locJobEntryRecord: locJobEntryRecord_Next});
    Reset(tmr_Options_PopulateCollection);
    UpdateContext({locLoopRepeat: true}),
    // Else,no parent found,end looping
    Reset(tmr_Options_PopulateCollection);
    UpdateContext({locLoopRepeat: false});
    // focus on last record
    If(
        Last(
            Sort(
                colJobEntryOptionHierarchy,
                RowNumber,
                SortOrder.Descending
            )
        ).Type = gblOptionSets.JobEntryOption.Type.Attribute,
        Patch(
            colJobEntryOptionHierarchy,
            Defaults(colJobEntryOptionHierarchy),
            {RowNumber: 0}
        );
        Set(
            gblRecordJobEntryOption_Hierarchy,
            LookUp(
                AddColumns(
                    colCdsJobEntryOptions,
                    RowNumber,
                    0
                ),
                'Parent Option'.'Job Entry Option' = gblRecordJobEntryOption_Hierarchy.'Job Entry Option'
            )
        ),
        Set(
            gblRecordJobEntryOption_Hierarchy,
            Last(
                Sort(
                    colJobEntryOptionHierarchy,
                    RowNumber,
                    SortOrder.Descending
                )
            )
        );
        // TEST //
        If(
            gblRecordJobEntryOption_Hierarchy.Type = gblOptionSets.JobEntryOption.Type.Value,
            UpdateContext(
            {
                locSelectedValue: LookUp(
                    colCdsJobEntryOptions,
                    colCdsJobEntryOptions[@'Job Entry Option'] = gblRecordJobEntryOption_Hierarchy.'Job Entry Option'
                )
            }
        )
        // TEST //
    );
    UpdateContext({locShowSaveButton: true});
    );
    UpdateContext({locLoadingCompleted: true});

);
